// src/App.jsx
import { useState, useEffect } from 'react'
import { onAuthStateChanged, signInWithPopup, signOut } from 'firebase/auth'
import { doc, getDoc, setDoc, serverTimestamp } from 'firebase/firestore'
import { auth, db, provider } from './firebase.js'
import PlannerApp from './planner/PlannerApp.jsx'
import AdminPanel from './planner/AdminPanel.jsx'

const ADMIN_EMAIL = 'zc473@scarletmail.rutgers.edu'
const FONTS = `@import url('https://fonts.googleapis.com/css2?family=DM+Serif+Display&family=DM+Mono:wght@400;500;600&family=DM+Sans:wght@400;500;600&display=swap');`


const IMG_DOGS = "data:image/jpeg;base64,"
const IMG_CATS = "data:image/jpeg;base64,"
const IMG_DOGS_SM = "data:image/jpeg;base64,"
const IMG_CATS_SM = "data:image/jpeg;base64,"

async function checkWhitelist(email) {
  const ref = doc(db, 'whitelist', email.toLowerCase())
  const snap = await getDoc(ref)
  return snap.exists()
}
async function recordLogin(email, displayName, photoURL) {
  const ref = doc(db, 'whitelist', email.toLowerCase())
  await setDoc(ref, { email: email.toLowerCase(), displayName: displayName||'', photoURL: photoURL||'', lastLogin: serverTimestamp() }, { merge: true })
}

function Footer({ lang }) {
  const en = lang === 'en'
  return (
    <div style={{ borderTop: '1px solid rgba(255,255,255,0.06)', marginTop: 32, padding: '20px 24px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 14 }}>
      <div style={{ display: 'flex', gap: 6 }}>
        <img src={IMG_DOGS_SM} alt="dogs" style={{ width: 32, height: 32, borderRadius: '50%', objectFit: 'cover', border: '1.5px solid rgba(255,255,255,0.15)' }}/>
        <img src={IMG_CATS_SM} alt="cats" style={{ width: 32, height: 32, borderRadius: '50%', objectFit: 'cover', border: '1.5px solid rgba(255,255,255,0.15)' }}/>
      </div>
      <div style={{ fontSize: 11, color: '#334155', fontFamily: 'monospace', lineHeight: 1.6 }}>
        <span style={{ color: '#475569' }}>Designed by Zhihang</span>
        <span style={{ margin: '0 6px', opacity: 0.3 }}>·</span>
        <a href="mailto:zhihang.chen@rutgers.edu" style={{ color: '#2563eb', textDecoration: 'none', opacity: 0.8 }}>zhihang.chen@rutgers.edu</a>
      </div>
    </div>
  )
}

function Shell({ children, lang, setLang }) {
  const en = lang === 'en'
  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg,#0f172a,#1e293b)', display: 'flex', flexDirection: 'column', fontFamily: 'sans-serif' }}>
      <style>{FONTS}</style>
      <button onClick={() => setLang(l => l === 'en' ? 'zh' : 'en')}
        style={{ position: 'fixed', top: 16, right: 16, background: 'rgba(255,255,255,0.07)', border: '1px solid rgba(255,255,255,0.1)', color: '#94a3b8', borderRadius: 20, padding: '5px 14px', fontSize: 11, cursor: 'pointer', fontFamily: 'monospace', zIndex: 10 }}>
        {en ? '中文' : 'English'}
      </button>
      <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24 }}>
        <div style={{ width: '100%', maxWidth: 420 }}>
          {children}
        </div>
      </div>
      <Footer lang={lang}/>
    </div>
  )
}

function LoginScreen({ lang, setLang, onSignIn, loading, error }) {
  const en = lang === 'en'
  return (
    <Shell lang={lang} setLang={setLang}>
      <div style={{ textAlign: 'center', marginBottom: 24 }}>
        <div style={{ fontFamily: "'DM Serif Display',serif", fontSize: 28, color: '#f8fafc', marginBottom: 6 }}>
          {en ? 'WB Planner' : 'WB 规划器'}
        </div>
        <div style={{ fontSize: 11, color: '#475569', letterSpacing: 1, fontFamily: 'monospace' }}>
          {en ? 'Lab Internal Tool' : '实验室内部工具'}
        </div>
      </div>

      {/* Two photos side by side */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 22, borderRadius: 12, overflow: 'hidden', height: 160 }}>
        <img src={IMG_DOGS} alt="lab dogs" style={{ flex: 1, width: '50%', objectFit: 'cover', objectPosition: 'center top' }}/>
        <img src={IMG_CATS} alt="lab cats" style={{ flex: 1, width: '50%', objectFit: 'cover' }}/>
      </div>

      <div style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: 14, padding: '22px 20px', display: 'flex', flexDirection: 'column', gap: 14, alignItems: 'center' }}>
        <div style={{ fontSize: 13, color: '#94a3b8', textAlign: 'center', lineHeight: 1.6 }}>
          {en ? 'Sign in with your Google account to access the lab planner.' : '使用 Google 账号登录以访问实验室规划器。'}
        </div>
        {error && (
          <div style={{ width: '100%', fontSize: 12, color: '#f87171', background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', borderRadius: 8, padding: '10px 14px', textAlign: 'center' }}>
            {error}
          </div>
        )}
        <button onClick={onSignIn} disabled={loading}
          style={{ width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 12, padding: '13px 20px', background: loading ? 'rgba(255,255,255,0.05)' : '#fff', color: '#1e293b', border: 'none', borderRadius: 10, fontSize: 14, fontWeight: 600, cursor: loading ? 'not-allowed' : 'pointer', opacity: loading ? 0.6 : 1 }}>
          {!loading && (
            <svg width="18" height="18" viewBox="0 0 48 48">
              <path fill="#4285F4" d="M44.5 20H24v8.5h11.8C34.7 33.9 30.1 37 24 37c-7.2 0-13-5.8-13-13s5.8-13 13-13c3.1 0 5.9 1.1 8.1 2.9l6.4-6.4C34.6 4.1 29.6 2 24 2 11.8 2 2 11.8 2 24s9.8 22 22 22c11 0 21-8 21-22 0-1.3-.2-2.7-.5-4z"/>
              <path fill="#34A853" d="M6.3 14.7l7 5.1C15.1 16.1 19.2 13 24 13c3.1 0 5.9 1.1 8.1 2.9l6.4-6.4C34.6 4.1 29.6 2 24 2 16.3 2 9.7 7.4 6.3 14.7z"/>
              <path fill="#FBBC05" d="M24 46c5.8 0 10.7-1.9 14.3-5.2l-6.6-5.4C29.9 37 27.1 38 24 38c-6 0-11.1-4-12.9-9.5l-7 5.4C7.6 41.9 15.2 46 24 46z"/>
              <path fill="#EA4335" d="M44.5 20H24v8.5h11.8c-.9 2.5-2.6 4.6-4.8 6l6.6 5.4C41.6 36.2 45 30.5 45 24c0-1.3-.2-2.7-.5-4z"/>
            </svg>
          )}
          {loading ? (en ? 'Signing in…' : '登录中…') : (en ? 'Sign in with Google' : '使用 Google 账号登录')}
        </button>
        <div style={{ fontSize: 11, color: '#334155', fontFamily: 'monospace', textAlign: 'center' }}>
          {en ? 'Access is restricted to approved lab members.' : '仅限实验室成员访问，需管理员授权。'}
        </div>
      </div>
    </Shell>
  )
}

function AccessDenied({ lang, setLang, user, onSignOut }) {
  const en = lang === 'en'
  return (
    <Shell lang={lang} setLang={setLang}>
      <div style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(239,68,68,0.2)', borderRadius: 14, padding: '28px 24px', display: 'flex', flexDirection: 'column', gap: 14, alignItems: 'center', textAlign: 'center' }}>
        <div style={{ fontSize: 32 }}>🔒</div>
        <div style={{ fontSize: 15, fontWeight: 700, color: '#f87171' }}>{en ? 'Access Not Granted' : '暂无访问权限'}</div>
        <div style={{ fontSize: 13, color: '#94a3b8', lineHeight: 1.7 }}>
          {en ? <>{'Your account '}<strong style={{ color: '#cbd5e1' }}>{user?.email}</strong>{' has not been added to the lab whitelist.'}</> : <>{'你的账号 '}<strong style={{ color: '#cbd5e1' }}>{user?.email}</strong>{' 尚未被加入白名单。'}</>}
        </div>
        <div style={{ fontSize: 13, color: '#64748b', background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: 8, padding: '12px 16px', width: '100%' }}>
          {en ? 'Contact the lab admin to request access:' : '请联系管理员申请访问权限：'}
          <div style={{ marginTop: 6, fontFamily: 'monospace', fontSize: 12, color: '#93c5fd' }}>{ADMIN_EMAIL}</div>
        </div>
        <button onClick={onSignOut} style={{ padding: '9px 20px', background: 'rgba(255,255,255,0.07)', color: '#94a3b8', border: '1px solid rgba(255,255,255,0.1)', borderRadius: 8, fontSize: 13, cursor: 'pointer' }}>
          {en ? 'Sign out' : '退出登录'}
        </button>
      </div>
    </Shell>
  )
}

export default function App() {
  const [lang, setLang]           = useState('en')
  const [authUser, setAuthUser]   = useState(null)
  const [screen, setScreen]       = useState('loading')
  const [loginErr, setLoginErr]   = useState('')
  const [signingIn, setSigningIn] = useState(false)
  const isAdmin = authUser?.email?.toLowerCase() === ADMIN_EMAIL.toLowerCase()

  useEffect(() => {
    const unsub = onAuthStateChanged(auth, async (user) => {
      if (!user) { setAuthUser(null); setScreen('login'); return }
      setAuthUser(user)
      const email = user.email.toLowerCase()
      if (email === ADMIN_EMAIL.toLowerCase()) {
        await recordLogin(user.email, user.displayName, user.photoURL)
        setScreen('admin'); return
      }
      const allowed = await checkWhitelist(email)
      if (allowed) { await recordLogin(user.email, user.displayName, user.photoURL); setScreen('planner') }
      else setScreen('denied')
    })
    return unsub
  }, [])

  const handleSignIn = async () => {
    setLoginErr(''); setSigningIn(true)
    try { await signInWithPopup(auth, provider) }
    catch (e) { if (e.code !== 'auth/popup-closed-by-user') setLoginErr('Sign-in failed. Please try again.') }
    setSigningIn(false)
  }
  const handleSignOut = async () => { await signOut(auth); setAuthUser(null); setScreen('login') }

  if (screen === 'loading') return (
    <div style={{ minHeight: '100vh', background: '#0f172a', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <style>{FONTS}</style>
      <div style={{ fontFamily: "'DM Serif Display',serif", color: '#475569', fontSize: 20 }}>WB Planner…</div>
    </div>
  )
  if (screen === 'login')   return <LoginScreen lang={lang} setLang={setLang} onSignIn={handleSignIn} loading={signingIn} error={loginErr}/>
  if (screen === 'denied')  return <AccessDenied lang={lang} setLang={setLang} user={authUser} onSignOut={handleSignOut}/>
  if (screen === 'admin')   return <AdminPanel lang={lang} setLang={setLang} user={authUser} isAdmin={isAdmin} onEnterPlanner={() => setScreen('planner')} onSignOut={handleSignOut}/>
  if (screen === 'planner') return <PlannerApp lang={lang} setLang={setLang} user={authUser} isAdmin={isAdmin} onAdminPanel={() => setScreen('admin')} onSignOut={handleSignOut}/>
  return null
}
